// === DISPATCH: prepare les articles + dossier de sortie unique ===
const input = $input.first().json;
const body = input.body || input;
const mode = body.mode || 'screening';
const articles = body.articles || [];
const question = body.question || '';
const criteria = body.criteria || '';
const extractFields = body.extract_fields || null;
// Format de sortie choisi par l'user (ris/nbib/bib) - RIS par defaut pour back-compat
const outputFormat = ((body.output_format || 'ris') + '').toLowerCase().trim();
const validFormats = ['ris', 'nbib', 'bib'];
const safeOutputFormat = validFormats.includes(outputFormat) ? outputFormat : 'ris';


console.log('Module: ' + mode + ' avec ' + articles.length + ' articles');

if (articles.length === 0) {
  return [{ json: { error: 'Aucun article fourni', mode } }];
}

// Generer un dossier de sortie unique : /desktop/ultralab-module-<mode>-<YYYYMMDD-HHMM>/
const now = new Date();
const pad = n => String(n).padStart(2, '0');
const timestamp = now.getFullYear() + pad(now.getMonth()+1) + pad(now.getDate()) + '-' + pad(now.getHours()) + pad(now.getMinutes());
const folderName = 'ultralab-module-' + mode + '-' + timestamp;
// D.8 custom output_folder : si l'user a choisi un dossier custom via UI, on l'utilise.
// Sinon default : /desktop/ultralab-module-<mode>-<timestamp>/
const userOutputFolder = (body.output_folder && typeof body.output_folder === 'string') ? body.output_folder.trim().replace(/\/+$/, '') : '';
let outputFolder;
if (userOutputFolder && userOutputFolder.startsWith('/desktop')) {
  // Path Docker valide (commence par /desktop) -> on append le sub-folder mode-timestamp
  outputFolder = userOutputFolder + '/' + folderName;
} else {
  outputFolder = '/desktop/' + folderName;
}
console.log('Dossier de sortie : ' + outputFolder);

// Enrichir le premier article avec question/criteres + output_folder partout
const enriched = articles.map((a, i) => {
  const article = { ...a, output_folder: outputFolder, _module_mode: mode, _folder_name: folderName };
  if (i === 0) {
    article.question = question;
    article.criteria = criteria;
    article.prefilter_enabled = false;
    if (extractFields) article.extract_fields = extractFields;
    // Skip flags : on saute les autres etapes (juste le module demande)
    article.skip_ranking = mode !== 'ranking';
    article.skip_clustering = mode !== 'clustering';
    article.skip_screening = mode !== 'screening';
    article.skip_pdf = mode !== 'pdf-fetch';
    article._output_format = safeOutputFormat;
  }
  // Pour le PDF fetch, marquer tous comme Include si pas de screening_decision
  if (mode === 'pdf-fetch' && !article.screening_decision) {
    article.screening_decision = 'Include';
  }
  return { json: article };
});


// PROGRESS_START_v1
try { await this.helpers.httpRequest({ method:'POST', url:'http://host.docker.internal:8080/api/module-progress/start', body:JSON.stringify({mode:mode, total:articles.length, label:mode}), headers:{'Content-Type':'application/json'}, timeout:3000 }); } catch(e) {}
return enriched;

// === ASSEMBLE + EXPORT MODULE RESULTS ===
// Refactor 0.4.3 : le monolithe par phases (stats / RIS / XLSX / rapport melanges par de
// longs if(mode===...)) est reorganise en ROUTEUR PAR MODULE. La logique propre a chaque
// module (pure, sans I/O) vit dans une entree unique de MODULES[mode] :
//   { statsInto, risNote, columns, styleSheet, extraSheets, reportSection }
// Des squelettes generiques (buildRIS / buildXLSX / buildReport) consomment ces entrees.
// L'orchestrateur async reste lineaire (calcul stats -> fichiers coeur -> fichiers annexes
// -> methods.json -> retour). Comportement identique a l'ancien node (verifie golden + harness).
const XLSX = require('xlsx');
const PROXY = 'http://host.docker.internal:3456';
const items = $input.all();
const articles = items.map(i => i.json);
const mode = (articles[0] && articles[0]._module_mode) || 'unknown';
const outputFolder = (articles[0] && articles[0].output_folder) || '/desktop/ultralab-module-output';
const folderName = (articles[0] && articles[0]._folder_name) || 'ultralab-module-output';

// ===================================================================================
// HELPERS PARTAGES (mode-agnostiques)
// ===================================================================================
//<<<PURE_START>>>
function __pEsc(s){ return String(s == null ? '' : s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

// PRISMA_FLOW_HTML_v1 - diagramme de flux visuel + stats detaillees (screening / fulltext)
function buildPrismaHtml(m, arts, st, a0) {
  const isFT = (m === 'fulltext-screening');
  let inc, may, exc, screened, label;
  if (isFT) { inc = st.include_final||0; may = st.maybe_final||0; exc = st.exclude_final||0; screened = st.total_evaluated || (inc+may+exc); label = 'Articles en texte intégral évalués pour éligibilité'; }
  else { inc = st.include||0; may = st.maybe||0; exc = st.exclude||0; screened = inc+may+exc; label = 'Notices examinées (titre / résumé)'; }
  const needsReview = arts.filter(function(a){ return a._needs_human_review; }).length;
  var __kraw = isFT ? (a0 && a0._fulltext_kappa) : (a0 && a0._screening_kappa); const kap = (__kraw && __kraw.enabled) ? __kraw : null;
  const conf = { high:0, medium:0, low:0, none:0 };
  arts.forEach(function(a){ const c=(a.screening_confidence||'').toLowerCase(); if(conf[c]!==undefined) conf[c]++; else conf.none++; });
  const tot = screened || 1;
  const q = __pEsc(a0.question||''); const crit = __pEsc(a0.criteria||'');
  const h = [];
  h.push('<!DOCTYPE html><html lang="fr"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1">');
  h.push('<title>PRISMA - ' + (isFT?'Lecture integrale':'Pre-screening') + '</title><style>');
  h.push('body{font-family:-apple-system,Segoe UI,Roboto,sans-serif;background:#f5f6fa;color:#222;margin:0;padding:24px;}');
  h.push('h1{font-size:20px;color:#1a237e;}h2{font-size:15px;color:#37474f;margin-top:26px;}');
  h.push('.flow{display:flex;flex-direction:column;align-items:center;margin:16px 0;}');
  h.push('.box{border:2px solid #3f51b5;border-radius:8px;padding:12px 18px;background:#fff;text-align:center;min-width:280px;box-shadow:0 1px 4px rgba(0,0,0,.08);}');
  h.push('.box .n{font-size:22px;font-weight:700;}.box .l{font-size:12px;color:#555;}');
  h.push('.arrow{width:0;height:0;border-left:9px solid transparent;border-right:9px solid transparent;border-top:13px solid #3f51b5;margin:8px 0;}');
  h.push('.row{display:flex;gap:14px;justify-content:center;flex-wrap:wrap;}');
  h.push('.dbox{border-radius:8px;padding:12px 16px;color:#fff;text-align:center;min-width:140px;}.dbox .n{font-size:22px;font-weight:700;}');
  h.push('.inc{background:#2e7d32;}.may{background:#ef6c00;}.exc{background:#c62828;}');
  h.push('.side{margin-top:16px;display:flex;gap:12px;justify-content:center;flex-wrap:wrap;}');
  h.push('.chip{background:#eceff1;border:1px solid #cfd8dc;border-radius:20px;padding:6px 14px;font-size:13px;}.chip b{color:#1a237e;}');
  h.push('table{border-collapse:collapse;margin:8px 0;}td,th{border:1px solid #ccc;padding:6px 12px;font-size:13px;text-align:left;}th{background:#3f51b5;color:#fff;}');
  h.push('.meta{font-size:12px;color:#666;max-width:760px;}</style></head><body>');
  h.push('<h1>Diagramme de flux PRISMA 2020 &mdash; ' + (isFT?'Lecture intégrale (full-text)':'Pré-screening IA (titre/résumé)') + '</h1>');
  if (q) h.push('<p class="meta"><b>Question :</b> ' + q + '</p>');
  h.push('<div class="flow"><div class="box"><div class="n">' + screened + '</div><div class="l">' + label + '</div></div>');
  h.push('<div class="arrow"></div>');
  h.push('<div class="row"><div class="dbox inc"><div class="n">' + inc + '</div><div>Inclus</div></div>');
  h.push('<div class="dbox may"><div class="n">' + may + '</div><div>Incertain</div></div>');
  h.push('<div class="dbox exc"><div class="n">' + exc + '</div><div>Exclus</div></div></div></div>');
  h.push('<div class="side"><div class="chip">Vérification humaine recommandée : <b>' + needsReview + '</b></div>');
  if (kap) h.push('<div class="chip">Accord inter-juges (' + __pEsc(kap.model_1) + ' vs ' + __pEsc(kap.model_2) + ') : <b>kappa = ' + kap.cohen_kappa + '</b> (' + __pEsc(kap.kappa_interpretation) + '), ' + kap.n_disagree + ' désaccords</div>');
  h.push('</div>');
  h.push('<h2>Détail des décisions</h2><table><tr><th>Decision</th><th>N</th><th>%</th></tr>');
  h.push('<tr><td>Inclus</td><td>' + inc + '</td><td>' + Math.round(inc/tot*100) + '%</td></tr>');
  h.push('<tr><td>Incertain</td><td>' + may + '</td><td>' + Math.round(may/tot*100) + '%</td></tr>');
  h.push('<tr><td>Exclus</td><td>' + exc + '</td><td>' + Math.round(exc/tot*100) + '%</td></tr></table>');
  // PRISMA_EXCL_REASONS_v1 - motifs d'exclusion agreges depuis l'audit critere-par-critere (F1)
  if (exc > 0) {
    var __er = {};
    for (var __xi = 0; __xi < arts.length; __xi++) {
      var __xa = arts[__xi];
      var __xdec = isFT ? __xa.screening_decision_fulltext : __xa.screening_decision;
      if (__xdec !== 'Exclude') continue;
      var __labels = [];
      var __ct = __xa.screening_criteria || '';
      if (__ct) {
        var __parts = __ct.split(';');
        for (var __pi = 0; __pi < __parts.length; __pi++) {
          var __eq = __parts[__pi].indexOf('=');
          if (__eq < 0) continue;
          var __lab = __parts[__pi].slice(0, __eq).trim();
          var __val = __parts[__pi].slice(__eq + 1).trim().toLowerCase();
          if (!__lab || !__val) continue;
          var __met = (__val.indexOf('met') === 0) || (__val.indexOf('ok') === 0) || (__val.indexOf('oui') === 0) || (__val.indexOf('yes') === 0) || (__val.indexOf('rempli') === 0) || (__val.indexOf('conforme') === 0);
          if (!__met) __labels.push(__lab);
        }
      }
      if (__labels.length === 0) {
        var __rsn = (isFT ? __xa.screening_reason_fulltext : __xa.screening_reason) || '';
        __rsn = String(__rsn).replace(/^crit[eè]res?\s*:\s*/i, '').trim();
        __labels.push(__rsn ? __rsn.substring(0, 60) : '(non precise)');
      }
      for (var __li = 0; __li < __labels.length; __li++) { var __k = __labels[__li]; __er[__k] = (__er[__k] || 0) + 1; }
    }
    var __ekeys = Object.keys(__er).sort(function(a, b){ return __er[b] - __er[a]; }).slice(0, 8);
    if (__ekeys.length) {
      h.push('<h2>Motifs d&rsquo;exclusion (PRISMA 2020 &mdash; excluded with reasons)</h2>');
      h.push('<table><tr><th>Critere / motif</th><th>Articles exclus</th></tr>');
      for (var __ek = 0; __ek < __ekeys.length; __ek++) { h.push('<tr><td>' + __pEsc(__ekeys[__ek]) + '</td><td>' + __er[__ekeys[__ek]] + '</td></tr>'); }
      h.push('</table>');
    }
  }
  if (!isFT) { h.push('<h2>Niveau de confiance IA</h2><table><tr><th>Confiance</th><th>N</th></tr>'); h.push('<tr><td>Élevée</td><td>' + conf.high + '</td></tr><tr><td>Moyenne</td><td>' + conf.medium + '</td></tr><tr><td>Faible</td><td>' + conf.low + '</td></tr>' + (conf.none?('<tr><td>Non renseignée</td><td>' + conf.none + '</td></tr>'):'') + '</table>'); }
  if (crit) h.push('<h2>Critères</h2><p class="meta">' + crit + '</p>');
  h.push('<p class="meta">Généré par UltraLab. Le pré-screening IA est indicatif et requiert une validation humaine.</p></body></html>');
  return h.join('');
}

// DISAGREEMENTS_VIEW_v1 - vue resolution des desaccords (3e relecteur)
function __disagWrap(phase, body) {
  return '<!DOCTYPE html><html lang="fr"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1"><style>body{font-family:-apple-system,Segoe UI,Roboto,sans-serif;background:#f5f6fa;color:#222;padding:24px;}h1{font-size:19px;color:#b71c1c;}table{border-collapse:collapse;width:100%;margin-top:10px;}td,th{border:1px solid #ccc;padding:6px 10px;font-size:13px;text-align:left;vertical-align:top;}th{background:#b71c1c;color:#fff;}.meta{font-size:12px;color:#666;max-width:760px;}</style></head><body><h1>Désaccords à arbitrer &mdash; ' + phase + ' (3e relecteur)</h1><p class="meta">Articles où les deux modèles divergent. À trancher par un relecteur humain.</p>' + body + '</body></html>';
}
function buildDisagreementsHtml(m, arts) {
  var isFT = (m === 'fulltext-screening');
  var rows = [];
  if (m === 'extraction') {
    for (var i = 0; i < arts.length; i++) {
      var a = arts[i]; var fa = a._extraction_field_agreement; if (!fa) continue;
      var bad = Object.keys(fa).filter(function(k){ return !fa[k]; }); if (!bad.length) continue;
      var e1 = a._extracted || {}, e2 = a._extracted_2 || {};
      var cells = bad.map(function(k){ return '<div style="margin:2px 0;"><b>' + __pEsc(k) + '</b> &mdash; M1: ' + __pEsc(String(e1[k] == null ? '(vide)' : e1[k])).substring(0,140) + ' | M2: ' + __pEsc(String(e2[k] == null ? '(vide)' : e2[k])).substring(0,140) + '</div>'; }).join('');
      rows.push('<tr><td>' + __pEsc((a.title||'').substring(0,90)) + '</td><td>' + (a._extraction_agreement != null ? a._extraction_agreement + '%' : '') + '</td><td>' + cells + '</td></tr>');
    }
    if (!rows.length) return null;
    return __disagWrap('Extraction', '<table><tr><th>Article</th><th>Accord</th><th>Champs en désaccord (M1 vs M2)</th></tr>' + rows.join('') + '</table>');
  } else {
    var dk = isFT ? 'screening_agreement_fulltext' : 'screening_agreement';
    var d1k = isFT ? 'screening_decision_fulltext' : 'screening_decision';
    var d2k = isFT ? 'screening_decision_fulltext_2' : 'screening_decision_2';
    for (var j = 0; j < arts.length; j++) {
      var x = arts[j]; if (x[dk] !== 'disagree') continue;
      rows.push('<tr><td>' + __pEsc((x.title||'').substring(0,110)) + '</td><td>' + __pEsc(x[d1k]||'') + '</td><td>' + __pEsc(x[d2k]||'') + '</td><td></td></tr>');
    }
    if (!rows.length) return null;
    return __disagWrap(isFT ? 'Lecture intégrale' : 'Screening', '<table><tr><th>Article</th><th>Décision M1</th><th>Décision M2</th><th>Arbitrage humain</th></tr>' + rows.join('') + '</table>');
  }
}

// Hardening XLSX : tronque cellules a 32700 chars + retire chars de controle (partage)
function safeCell(v) {
  if (v === null || v === undefined) return '';
  if (typeof v === 'number' || typeof v === 'boolean') return v;
  let s = (typeof v === 'string') ? v : (typeof v === 'object' ? JSON.stringify(v) : String(v));
  // Retire caracteres de controle (sauf tab, LF, CR)
  s = s.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, ' ');
  if (s.length > 32700) {
    s = s.substring(0, 32700) + ' [tronque a 32700 chars]';
  }
  return s;
}

// === ECRIRE LES FICHIERS VIA LE PROXY ===
async function saveFile(savePath, content, isBase64) {
  try {
    const body = isBase64 ? { save_to: savePath, content_base64: content } : { save_to: savePath, content };
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: PROXY + '/save',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
      timeout: 60000
    });
    return resp && resp.success;
  } catch (e) {
    console.log('Save error: ' + e.message);
    return false;
  }
}

// === D.6 phase 2 : Generer le fichier .nbib (format MEDLINE) des articles uniques ===
function buildNbib(articles) {
  function fmt(tag, value) {
    if (!value && value !== 0) return '';
    const v = String(value).replace(/\r/g, '').replace(/\n/g, ' ').trim();
    if (!v) return '';
    return tag.padEnd(4) + '- ' + v + '\n';
  }
  function toEntry(a) {
    let out = '';
    if (a.pmid) out += fmt('PMID', a.pmid);
    out += fmt('OWN', 'NLM');
    out += fmt('STAT', 'MEDLINE');
    out += fmt('PT', 'Journal Article');
    out += fmt('TI', a.title);
    if (Array.isArray(a.authors)) {
      for (const au of a.authors) {
        if (!au) continue;
        out += fmt('FAU', au);
        const parts = au.trim().split(/\s+/);
        if (parts.length >= 2) {
          const last = parts[parts.length - 1];
          const initials = parts.slice(0, -1).map(p => p.charAt(0).toUpperCase()).join('');
          out += fmt('AU', last + ' ' + initials);
        } else {
          out += fmt('AU', au);
        }
      }
    }
    if (a.journal) { out += fmt('JT', a.journal); out += fmt('TA', a.journal); }
    if (a.volume) out += fmt('VI', a.volume);
    if (a.issue) out += fmt('IP', a.issue);
    if (a.pages) out += fmt('PG', a.pages);
    if (a.year) out += fmt('DP', a.year);
    if (a.abstract) out += fmt('AB', a.abstract);
    if (a.doi) {
      out += fmt('AID', a.doi + ' [doi]');
      out += fmt('LID', a.doi + ' [doi]');
    }
    if (a._source) out += fmt('SO', '[source:' + a._source + ']');
    return out + '\n';
  }
  return articles.map(toEntry).join('');
}

// Format BibTeX/LaTeX (.bib) pour les articles
function buildBibTeX(articles) {
  function escapeBib(s) {
    if (!s) return '';
    return String(s)
      .replace(/\\/g, '\\textbackslash{}')
      .replace(/[{}]/g, '')  // pas d'accolades dans les valeurs
      .replace(/[#$%&_]/g, '\\$&')  // chars speciaux LaTeX
      .replace(/[\r\n]+/g, ' ')
      .trim();
  }
  function makeKey(a, i) {
    // cle = 1er auteur (surname) + annee + index (anti-doublon)
    let surname = '';
    if (Array.isArray(a.authors) && a.authors.length > 0) {
      const parts = String(a.authors[0]).trim().split(/\s+/);
      surname = (parts[parts.length - 1] || '').replace(/[^a-zA-Z]/g, '');
    }
    const year = (a.year || 'NA').toString().match(/\d{4}/);
    return (surname || 'anon') + (year ? year[0] : 'NA') + '_' + (i + 1);
  }
  return articles.map((a, i) => {
    const key = makeKey(a, i);
    const authors = Array.isArray(a.authors) ? a.authors.map(escapeBib).join(' and ') : escapeBib(a.authors || '');
    let entry = '@article{' + key + ',\n';
    if (a.title) entry += '  title = {' + escapeBib(a.title) + '},\n';
    if (authors) entry += '  author = {' + authors + '},\n';
    if (a.journal) entry += '  journal = {' + escapeBib(a.journal) + '},\n';
    if (a.year) entry += '  year = {' + escapeBib(a.year) + '},\n';
    if (a.volume) entry += '  volume = {' + escapeBib(a.volume) + '},\n';
    if (a.issue) entry += '  number = {' + escapeBib(a.issue) + '},\n';
    if (a.pages) entry += '  pages = {' + escapeBib(a.pages).replace('-', '--') + '},\n';
    if (a.doi) entry += '  doi = {' + escapeBib(a.doi) + '},\n';
    if (a.url) entry += '  url = {' + escapeBib(a.url) + '},\n';
    if (a.abstract) entry += '  abstract = {' + escapeBib(a.abstract).substring(0, 2000) + '},\n';
    if (a.pmid) entry += '  pmid = {' + escapeBib(a.pmid) + '},\n';
    entry += '}\n\n';
    return entry;
  }).join('');
}

// ===================================================================================
// ROUTEUR PAR MODULE : chaque entree porte la logique PURE propre au module.
//   statsInto(stats, articles)          -> mute l'objet stats (verbatim ancien bloc)
//   risNote(a)                          -> annotations N1 du .ris pour cet article
//   columns(articles)                   -> { headers, rows } de la feuille principale
//   styleSheet(ws, wsData)              -> coloration conditionnelle (optionnel)
//   extraSheets(wb, articles)           -> feuilles supplementaires (optionnel)
//   reportSection(articles, stats, a0)  -> section markdown propre au module
// ===================================================================================
const MODULES = {
  'screening': {
    statsInto(stats, articles) {
      stats.include = articles.filter(a => a.screening_decision === 'Include').length;
      stats.maybe = articles.filter(a => a.screening_decision === 'Maybe').length;
      stats.exclude = articles.filter(a => a.screening_decision === 'Exclude').length;
    },
    risNote(a) {
      let n = '';
      if (a.screening_decision) {
        n += 'N1  - screening:' + a.screening_decision + (a.screening_confidence ? ' (confidence:' + a.screening_confidence + (a._needs_human_review ? ',needs_human_review' : '') + ')' : (a._needs_human_review ? ' (needs_human_review)' : '')) + (a.screening_reason ? ' - ' + a.screening_reason : '') + '\n';
      }
      return n;
    },
    columns(articles) {
      const headers = ['Titre', 'Auteurs', 'Année', 'Journal', 'DOI', 'Décision', 'Confiance', 'Vérif. humaine', 'Décision M2', 'Accord', 'Critères', 'Justification', 'Abstract']; // SCREENING_CONFIDENCE_COLS_v1 SCREENING_DOUBLE_COLS_v1 SCREENING_PERCRIT_COL_v1
      const order = { 'Include': 0, 'Maybe': 1, 'Exclude': 2 };
      const sorted = [...articles].sort((a,b) => (order[a.screening_decision]||1) - (order[b.screening_decision]||1));
      const rows = sorted.map(a => [a.title||'', (a.authors||[]).join('; '), a.year||'', a.journal||'', a.doi||'', a.screening_decision||'Maybe', a.screening_confidence||'', (a._needs_human_review ? 'Oui' : ''), a.screening_decision_2||'', a.screening_agreement||'', a.screening_criteria||'', a.screening_reason||'', (a.abstract||'').substring(0,1000)]);
      return { headers, rows };
    },
    styleSheet(ws, wsData) {
      for (let r = 1; r < wsData.length; r++) {
        const cell = ws[XLSX.utils.encode_cell({ r, c: 5 })];
        if (cell) {
          const d = wsData[r][5];
          const bg = d === 'Include' ? '00B050' : (d === 'Exclude' ? 'FF0000' : 'FFA500');
          cell.s = { fill: { fgColor: { rgb: bg } }, font: { color: { rgb: 'FFFFFF' }, bold: true } };
        }
      }
    },
    reportSection(articles, stats, a0) {
      let r = '';
      const __kap = articles[0] && articles[0]._screening_kappa; // SCREENING_DOUBLE_REPORT_v1
      if (__kap && __kap.enabled) {
        r += '### Double relecture (accord inter-juges)\n\n';
        r += '- Modeles : ' + __kap.model_1 + ' vs ' + __kap.model_2 + '\n';
        r += '- Articles relus 2x : ' + __kap.n_double_rated + '\n';
        r += '- Accord : ' + (__kap.percent_agreement != null ? __kap.percent_agreement + '%' : 'n/a') + ' (' + __kap.n_agree + '/' + __kap.n_double_rated + ')\n';
        r += '- **kappa de Cohen : ' + __kap.cohen_kappa + '** (' + __kap.kappa_interpretation + ')\n';
        r += '- Desaccords renvoyes en verif. humaine : ' + __kap.n_disagree + '\n\n';
      }
      const inc = articles.filter(a => a.screening_decision === 'Include').slice(0, 10);
      const may = articles.filter(a => a.screening_decision === 'Maybe').slice(0, 5);
      r += '### Top 10 articles inclus\n\n';
      inc.forEach((a, i) => { r += (i+1) + '. **' + (a.title || '?').substring(0, 100) + '** _(' + (a.year || 'n.d.') + ')_\n   Confiance : ' + (a.screening_confidence || 'n/a') + (a._needs_human_review ? ' (verif. humaine recommandee)' : '') + ' - Raison : ' + (a.screening_reason || '').substring(0, 150) + '\n'; });
      r += '\n### Top 5 "Maybe" a re-examiner manuellement\n\n';
      may.forEach((a, i) => { r += (i+1) + '. ' + (a.title || '?').substring(0, 100) + ' - ' + (a.screening_reason || '').substring(0, 100) + '\n'; });
      return r;
    },
  },

  'ranking': {
    statsInto(stats, articles) {
      const scores = articles.map(a => a.score || 0);
      stats.avg_score = scores.length > 0 ? Math.round(scores.reduce((a,b) => a+b, 0) / scores.length) : 0;
      stats.high_score = scores.filter(s => s >= 70).length;
      stats.med_score = scores.filter(s => s >= 40 && s < 70).length;
      stats.low_score = scores.filter(s => s < 40).length;
    },
    risNote(a) {
      let n = '';
      if (a.score !== undefined) {
        n += 'N1  - relevance_score:' + a.score + (a.score_reason ? ' - ' + a.score_reason : '') + '\n';
      }
      return n;
    },
    columns(articles) {
      const headers = ['Score', 'Score M2', 'Écart', 'Titre', 'Auteurs', 'Année', 'Journal', 'DOI', 'Topic', 'Population', 'Methodology', 'Context', 'Justification', 'Abstract'];
      const sorted = [...articles].sort((a,b) => (b.score||0) - (a.score||0));
      const rows = sorted.map(a => {
        const bd = a.score_breakdown || {};
        return [a.score||0, (a.score_2 !== undefined ? a.score_2 : ''), (a.score_diff !== undefined ? a.score_diff : ''), a.title||'', (a.authors||[]).join('; '), a.year||'', a.journal||'', a.doi||'', bd.topic||'', bd.population||'', bd.methodology||'', bd.context||'', a.score_reason||'', (a.abstract||'').substring(0,1000)];
      });
      return { headers, rows };
    },
    reportSection(articles, stats, a0) {
      let r = '';
      const top = [...articles].sort((a,b) => (b.score||0) - (a.score||0)).slice(0, 10);
      r += '### Top 10 articles par pertinence\n\n';
      top.forEach((a, i) => { r += (i+1) + '. **[' + (a.score||0) + '/100]** ' + (a.title || '?').substring(0, 100) + '\n   ' + (a.score_reason || '').substring(0, 150) + '\n'; });
      return r;
    },
  },

  'clustering': {
    statsInto(stats, articles) {
      const labels = new Set(articles.map(a => a.cluster_label).filter(Boolean));
      stats.clusters = labels.size;
      stats.cluster_list = [...labels];
    },
    risNote(a) {
      let n = '';
      if (a.cluster_label) {
        n += 'N1  - cluster:' + a.cluster_label + '\n';
      }
      return n;
    },
    columns(articles) {
      const headers = ['Cluster', 'Titre', 'Auteurs', 'Année', 'Journal', 'DOI', 'Abstract'];
      const sorted = [...articles].sort((a,b) => (a.cluster_label||'').localeCompare(b.cluster_label||''));
      const rows = sorted.map(a => [a.cluster_label||'Unclustered', a.title||'', (a.authors||[]).join('; '), a.year||'', a.journal||'', a.doi||'', (a.abstract||'').substring(0,1000)]);
      return { headers, rows };
    },
    reportSection(articles, stats, a0) {
      let r = '';
      const byCluster = {};
      articles.forEach(a => { const c = a.cluster_label || 'Unclustered'; (byCluster[c] = byCluster[c] || []).push(a); });
      r += '### Clusters identifies\n\n';
      for (const c of Object.keys(byCluster)) {
        r += '- **' + c + '** : ' + byCluster[c].length + ' articles\n';
        byCluster[c].slice(0, 3).forEach(a => { r += '  - ' + (a.title || '?').substring(0, 90) + '\n'; });
      }
      return r;
    },
  },

  'pdf-fetch': {
    statsInto(stats, articles) {
      stats.downloaded = articles.filter(a => a.pdf_local).length;
      stats.failed = articles.filter(a => a.pdf_url && !a.pdf_local).length;
      stats.no_doi = articles.filter(a => !a.doi).length;
      // PDF_COVERAGE_v1 : clarifier la couverture (exclus non tentes vs tentes)
      stats.total = articles.length;
      stats.attempted = articles.filter(a => a.screening_decision === 'Include' || a.screening_decision === 'Maybe').length;
      stats.excluded_not_fetched = articles.filter(a => a.screening_decision === 'Exclude').length;
      stats.not_downloaded = Math.max(0, stats.attempted - stats.downloaded);
      // PDF_BY_SOURCE_v1 - repartition par source pour affichage UI
      stats.by_source = { zotero: 0, unpaywall: 0, core: 0, europepmc: 0, other: 0, none: 0 };
      for (const a of articles) {
        if (!a.pdf_local) {
          stats.by_source.none++;
          continue;
        }
        const src = (a.pdf_source || '').toLowerCase();
        if (src === 'zotero') stats.by_source.zotero++;
        else if (src === 'unpaywall') stats.by_source.unpaywall++;
        else if (src === 'core' || src === 'core.ac.uk') stats.by_source.core++;
        else if (src.indexOf('europe') === 0 || src === 'europepmc') stats.by_source.europepmc++;
        else stats.by_source.other++;
      }
    },
    columns(articles) {
      const headers = ['Titre', 'Auteurs', 'Année', 'DOI', 'PDF téléchargé', 'Source PDF', 'Chemin local', 'URL'];
      const rows = articles.map(a => [a.title||'', (a.authors||[]).join('; '), a.year||'', a.doi||'', a.pdf_local ? 'Oui' : 'Non', a.pdf_source||'', a.pdf_local||'', a.pdf_url||a.url||'']);
      return { headers, rows };
    },
    reportSection(articles, stats, a0) {
      let r = '';
      const ok = articles.filter(a => a.pdf_local).slice(0, 10);
      const ko = articles.filter(a => !a.pdf_local && !!a.doi).slice(0, 10);
      r += '### Top 10 PDFs telecharges\n\n';
      ok.forEach((a, i) => { r += (i+1) + '. ' + (a.title || '?').substring(0, 100) + ' [' + (a.pdf_source || '') + ']\n'; });
      r += '\n### Top 10 echecs (DOI sans PDF)\n\n';
      ko.forEach((a, i) => { r += (i+1) + '. ' + (a.title || '?').substring(0, 100) + ' - DOI : ' + a.doi + '\n'; });
      return r;
    },
  },

  'extraction': {
    statsInto(stats, articles) {
      stats.extracted_ok = articles.filter(a => a._extract_status === 'ok').length;
      stats.extracted_failed = articles.filter(a => a._extract_status && a._extract_status !== 'ok').length;
      stats.with_pdf = articles.filter(a => a._extract_source && a._extract_source.indexOf('PDF') === 0).length;
      stats.abstract_only = articles.filter(a => a._extract_source && a._extract_source.indexOf('abstract') === 0).length;
    },
    risNote(a) {
      let n = '';
      if (a._extracted) {
        for (const k of Object.keys(a._extracted)) {
          const v = String(a._extracted[k] || '').replace(/\n/g, ' ').substring(0, 500);
          if (v) n += 'N1  - ' + k + ':' + v + '\n';
        }
      }
      return n;
    },
    columns(articles) {
      // Recuperer dynamiquement les champs extraits du premier article
      const extractedKeys = new Set();
      articles.forEach(a => { if (a._extracted) Object.keys(a._extracted).forEach(k => extractedKeys.add(k)); });
      const fieldNames = [...extractedKeys];
      const headers = ['Titre', 'Auteurs', 'Année', 'DOI', 'Source extraction', 'Statut'].concat(fieldNames);
      const rows = articles.map(a => {
        const ext = a._extracted || {};
        return [a.title||'', (a.authors||[]).join('; '), a.year||'', a.doi||'', a._extract_source||'', a._extract_status||'']
          .concat(fieldNames.map(f => ext[f] !== undefined ? String(ext[f]) : ''));
      });
      return { headers, rows };
    },
    reportSection(articles, stats, a0) {
      let r = '';
      const ok = articles.filter(a => a._extract_status === 'ok').slice(0, 5);
      r += '### 5 premiers articles avec extraction reussie\n\n';
      ok.forEach((a, i) => {
        r += (i+1) + '. **' + (a.title || '?').substring(0, 100) + '**\n';
        const ext = a._extracted || {};
        for (const k of Object.keys(ext).slice(0, 5)) {
          r += '   - _' + k + '_ : ' + String(ext[k]).substring(0, 200) + '\n';
        }
      });
      return r;
    },
  },

  'fulltext-screening': {
    statsInto(stats, articles) {
      const confirmed = articles.filter(a => a._fulltext_status === 'confirmed').length;
      const revised = articles.filter(a => a._fulltext_status === 'revised').length;
      const no_pdf = articles.filter(a => a._fulltext_status === 'no_pdf').length;
      const extract_failed = articles.filter(a => a._fulltext_status === 'extract_failed').length;
      const llm_error = articles.filter(a => a._fulltext_status === 'llm_error').length;
      stats.confirmed = confirmed;
      stats.revised = revised;
      stats.no_pdf = no_pdf;
      stats.extract_failed = extract_failed;
      stats.llm_error = llm_error;
      stats.total_evaluated = confirmed + revised;
      // Stats sur les decisions finales (fulltext) - seulement pour les eligibles
      const eligibles = articles.filter(a => a.screening_decision_fulltext);
      stats.include_final = eligibles.filter(a => a.screening_decision_fulltext === 'Include').length;
      stats.maybe_final = eligibles.filter(a => a.screening_decision_fulltext === 'Maybe').length;
      stats.exclude_final = eligibles.filter(a => a.screening_decision_fulltext === 'Exclude').length;
    },
    columns(articles) {
      // FULLTEXT_REPORTING_v1
      const headers = ['Titre', 'Décision (fulltext)', 'Justification', 'Décision initiale', 'Statut', 'Auteurs', 'Année', 'Journal', 'DOI', 'PDF local'];
      const order = { 'Include': 0, 'Maybe': 1, 'Exclude': 2 };
      const evalable = articles.filter(a => a.screening_decision_fulltext);
      const skipped = articles.filter(a => !a.screening_decision_fulltext);
      const sorted = evalable.sort((a, b) => {
        const oa = order[a.screening_decision_fulltext];
        const ob = order[b.screening_decision_fulltext];
        return (oa === undefined ? 99 : oa) - (ob === undefined ? 99 : ob);
      }).concat(skipped);
      const rows = sorted.map(a => [
        a.title || '',
        a.screening_decision_fulltext || '(non evalue)',
        a.screening_reason_fulltext || a._fulltext_skipped || '',
        a.screening_decision_initial || '(aucune)',
        a._fulltext_status || (a._fulltext_skipped ? 'skipped' : ''),
        (a.authors || []).join('; '),
        a.year || '',
        a.journal || '',
        a.doi || '',
        a.pdf_local || ''
      ]);
      return { headers, rows };
    },
    reportSection(articles, stats, a0) {
      let r = '';
      // FULLTEXT_REPORTING_v1 - rapport detaille avec toutes les decisions
      r += '### Synthese\n\n';
      r += '- Articles evalues par le LLM : **' + (stats.total_evaluated || 0) + '**\n';
      r += '- Decision initiale confirmee : ' + (stats.confirmed || 0) + '\n';
      r += '- Decision revisee : **' + (stats.revised || 0) + '**\n';
      r += '- Non analyses (PDF absent / erreur extraction / erreur LLM) : ' + ((stats.no_pdf || 0) + (stats.extract_failed || 0) + (stats.llm_error || 0)) + '\n\n';
      r += '### Repartition finale\n\n';
      r += '- Include : ' + (stats.include_final || 0) + '\n';
      r += '- Maybe   : ' + (stats.maybe_final || 0) + '\n';
      r += '- Exclude : ' + (stats.exclude_final || 0) + '\n\n';

      const evalable = articles.filter(a => a.screening_decision_fulltext);
      const incs = evalable.filter(a => a.screening_decision_fulltext === 'Include');
      const mays = evalable.filter(a => a.screening_decision_fulltext === 'Maybe');
      const excs = evalable.filter(a => a.screening_decision_fulltext === 'Exclude');
      const skipped = articles.filter(a => !a.screening_decision_fulltext);

      if (incs.length > 0) {
        r += '### ✅ Include (' + incs.length + ')\n\n';
        incs.forEach(function(a, i) {
          r += (i + 1) + '. **' + (a.title || '?').substring(0, 160) + '**\n';
          if (a.screening_decision_initial) r += '   - _Decision initiale : ' + a.screening_decision_initial + '_\n';
          r += '   - _Justification (fulltext) :_ ' + (a.screening_reason_fulltext || '(non fournie)').substring(0, 350) + '\n';
          if (a.doi) r += '   - DOI : ' + a.doi + '\n';
          r += '\n';
        });
      }
      if (mays.length > 0) {
        r += '### ⚠️ Maybe (' + mays.length + ') - a re-examiner manuellement\n\n';
        mays.forEach(function(a, i) {
          r += (i + 1) + '. **' + (a.title || '?').substring(0, 160) + '**\n';
          if (a.screening_decision_initial) r += '   - _Decision initiale : ' + a.screening_decision_initial + '_\n';
          r += '   - _Justification :_ ' + (a.screening_reason_fulltext || '(non fournie)').substring(0, 350) + '\n';
          if (a.doi) r += '   - DOI : ' + a.doi + '\n';
          r += '\n';
        });
      }
      if (excs.length > 0) {
        r += '### ❌ Exclude (' + excs.length + ')\n\n';
        excs.forEach(function(a, i) {
          r += (i + 1) + '. ' + (a.title || '?').substring(0, 160) + '\n';
          r += '   - _Raison :_ ' + (a.screening_reason_fulltext || '(non fournie)').substring(0, 300) + '\n';
          if (a.doi) r += '   - DOI : ' + a.doi + '\n';
          r += '\n';
        });
      }
      if (skipped.length > 0) {
        r += '### ⏭️ Non analyses (' + skipped.length + ')\n\n';
        skipped.forEach(function(a, i) {
          const why = a._fulltext_skipped || a._fulltext_status || 'raison inconnue';
          r += (i + 1) + '. ' + (a.title || '?').substring(0, 160) + ' _(' + why + ')_\n';
        });
        r += '\n';
      }
      return r;
    },
  },

  'predatory-scan': {
    statsInto(stats, articles) {
      const byLevel = { low: 0, medium: 0, high: 0, critical: 0, unknown: 0 };
      let totalScore = 0;
      for (const a of articles) {
        const lvl = a._predatory_level || 'unknown';
        byLevel[lvl] = (byLevel[lvl] || 0) + 1;
        totalScore += (a._predatory_score || 0);
      }
      stats.low = byLevel.low;
      stats.medium = byLevel.medium;
      stats.high = byLevel.high;
      stats.critical = byLevel.critical;
      stats.to_review = (byLevel.high || 0) + (byLevel.critical || 0);
      stats.avg_score = articles.length > 0 ? Math.round(totalScore / articles.length) : 0;
    },
    columns(articles) {
      const headers = ['Score', 'Niveau', 'Drapeau', 'Titre', 'Journal', 'Publisher', 'DOI', 'ISSN', 'Année', 'Raisons', 'Rétractation'];
      // Tri par score decroissant (les plus risques en haut)
      const sorted = [...articles].sort((a, b) => (b._predatory_score || 0) - (a._predatory_score || 0));
      const rows = sorted.map(a => [
        a._predatory_score || 0,
        a._predatory_level || 'unknown',
        a._predatory_flag || 'gray',
        a.title || '',
        a.journal || '',
        a.publisher || (a._crossref_publisher || ''),
        a.doi || '',
        a.issn || a.ISSN || '',
        a.year || '',
        Array.isArray(a._predatory_reasons) ? a._predatory_reasons.join(' | ') : '',
        (a._retraction_status === 'retracted' ? 'RÉTRACTÉ' : (a._retraction_status === 'concern' ? 'Expression of concern' : ''))
      ]);
      return { headers, rows };
    },
    extraSheets(wb, articles) {
      // D.6 phase 2 : feuille "A revoir" pour mode predatory-scan (high + critical seulement)
      const toReview = articles
        .filter(a => a._predatory_level === 'high' || a._predatory_level === 'critical')
        .sort((a, b) => (b._predatory_score || 0) - (a._predatory_score || 0));
      if (toReview.length > 0) {
        const rvHeaders = ['Score', 'Niveau', 'Titre', 'Journal', 'Publisher', 'ISSN', 'Raisons (detail)'];
        const rvRows = toReview.map(a => [
          a._predatory_score || 0,
          a._predatory_level || '',
          a.title || '',
          a.journal || '',
          a.publisher || (a._crossref_publisher || ''),
          a.issn || a.ISSN || '',
          Array.isArray(a._predatory_reasons) ? a._predatory_reasons.join('\n') : ''
        ]);
        const rvData = [rvHeaders, ...rvRows].map(r => Array.isArray(r) ? r.map(safeCell) : r);
        const wsR = XLSX.utils.aoa_to_sheet(rvData);
        wsR['!cols'] = [{ wch: 8 }, { wch: 10 }, { wch: 50 }, { wch: 35 }, { wch: 25 }, { wch: 15 }, { wch: 60 }];
        XLSX.utils.book_append_sheet(wb, wsR, 'A revoir');
      }
    },
    reportSection(articles, stats, a0) {
      let r = '';
      r += '### Synthese du scan predatrices\n\n';
      r += '- Articles scannes : ' + (stats.total || articles.length) + '\n';
      r += '- Score moyen : ' + (stats.avg_score || 0) + '/100\n';
      r += '- A revoir (high + critical) : **' + (stats.to_review || 0) + '** articles\n\n';
      r += '### Repartition par niveau de risque\n\n';
      r += '- 🟢 LOW (0-25) : ' + (stats.low || 0) + ' articles\n';
      r += '- 🟠 MEDIUM (26-50) : ' + (stats.medium || 0) + ' articles\n';
      r += '- 🔴 HIGH (51-75) : ' + (stats.high || 0) + ' articles\n';
      r += '- 🔴 CRITICAL (76-100) : ' + (stats.critical || 0) + ' articles\n\n';
      const toReview = articles
        .filter(a => a._predatory_level === 'high' || a._predatory_level === 'critical')
        .sort((a, b) => (b._predatory_score || 0) - (a._predatory_score || 0))
        .slice(0, 10);
      if (toReview.length > 0) {
        r += '### Top 10 articles a revoir manuellement (risque eleve)\n\n';
        toReview.forEach((a, i) => {
          r += (i + 1) + '. **[Score ' + a._predatory_score + ' - ' + a._predatory_level.toUpperCase() + ']** ' + (a.title || '?').substring(0, 100) + '\n';
          r += '   Journal : ' + (a.journal || 'inconnu') + ' (' + (a.publisher || a._crossref_publisher || 'publisher inconnu') + ')\n';
          const reasons = Array.isArray(a._predatory_reasons) ? a._predatory_reasons.slice(0, 3) : [];
          for (const reason of reasons) r += '   - ' + reason + '\n';
        });
      }
      return r;
    },
  },

  'deduplicate': {
    statsInto(stats, articles) {
      stats.before = (articles[0] && articles[0]._total_before_dedup) || articles.length;
      stats.after = articles.length;
      stats.duplicates_removed = (articles[0] && articles[0]._duplicates_removed) || 0;
      stats.dedup_rate_pct = stats.before > 0 ? Math.round(stats.duplicates_removed / stats.before * 100) : 0;
    },
    columns(articles) {
      const headers = ['Titre', 'Auteurs', 'Année', 'Journal', 'DOI', 'Source', 'Clé dedup'];
      const rows = articles.map(a => [a.title||'', (a.authors||[]).join('; '), a.year||'', a.journal||'', a.doi||'', a.source||'', a._deduplication_key||'']);
      return { headers, rows };
    },
    extraSheets(wb, articles) {
      // D.6 phase 2 : feuille "Doublons" pour mode deduplicate
      const firstArt = articles[0] || {};
      const dedupReport = firstArt._dedup_report || null;
      if (dedupReport && Array.isArray(dedupReport.duplicates_detail) && dedupReport.duplicates_detail.length > 0) {
        const dupHeaders = ['Strategie', 'Confidence', 'Titre doublon', 'Titre master', 'Cle de match'];
        const dupRows = dedupReport.duplicates_detail.map(d => [
          d.strategy || '',
          d.confidence || '',
          d.duplicate_title || '',
          d.master_title || '',
          d.key_excerpt || ''
        ]);
        const dupData = [dupHeaders, ...dupRows].map(r => Array.isArray(r) ? r.map(safeCell) : r);
        const wsD = XLSX.utils.aoa_to_sheet(dupData);
        wsD['!cols'] = [{ wch: 18 }, { wch: 12 }, { wch: 50 }, { wch: 50 }, { wch: 30 }];
        if (dupData.length > 1) {
          wsD['!autofilter'] = { ref: XLSX.utils.encode_range({ s: { r: 0, c: 0 }, e: { r: dupData.length - 1, c: dupHeaders.length - 1 } }) };
        }
        XLSX.utils.book_append_sheet(wb, wsD, 'Doublons');
      }
    },
    reportSection(articles, stats, a0) {
      let r = '';
      r += '### Statistiques de deduplication\n\n';
      r += '- Articles initiaux : ' + (stats.before || 0) + '\n';
      r += '- Articles uniques apres dedup : ' + (stats.after || 0) + '\n';
      r += '- Doublons supprimes : ' + (stats.duplicates_removed || 0);
      r += ' (taux : ' + (stats.dedup_rate_pct || 0) + '%)\n\n';

      // D.6 phase 2 : exploite _dedup_report injecte par Dedup v2
      const firstArt = articles[0] || {};
      const dedupReport = firstArt._dedup_report || null;
      if (dedupReport) {
        r += '### Repartition par strategie de detection\n\n';
        const strat = dedupReport.strategies || {};
        r += '- DOI identique (high confidence) : ' + (strat.doi || 0) + '\n';
        r += '- Titre + annee + 1er auteur (medium confidence) : ' + (strat['title+year+author'] || 0) + '\n';
        r += '- Titre normalise seul (low confidence, a re-verifier) : ' + (strat['title-only'] || 0) + '\n\n';

        const bySrc = dedupReport.by_source || {};
        if (Object.keys(bySrc).length > 0) {
          r += '### Repartition des uniques par source\n\n';
          for (const k of Object.keys(bySrc)) {
            r += '- ' + k + ' : ' + bySrc[k] + ' articles\n';
          }
          r += '\n';
        }

        const dups = dedupReport.duplicates_detail || [];
        if (dups.length > 0) {
          r += '### Echantillon des 10 premiers doublons detectes\n\n';
          dups.slice(0, 10).forEach((d, i) => {
            r += (i + 1) + '. **Strategie : ' + d.strategy + '** (' + d.confidence + ')\n';
            r += '   - Doublon : ' + (d.duplicate_title || '?').substring(0, 100) + '\n';
            r += '   - Master  : ' + (d.master_title || '?').substring(0, 100) + '\n';
